import React,{useState} from "react";
import axios from "axios";

export default function ChatAssistant(){

const [text,setText]=useState("");
const [res,setRes]=useState("");

const ask=async()=>{
const r=await axios.post("http://localhost:8000/agent",{
action:"followup",
payload:{text}
})
setRes(JSON.stringify(r.data,null,2))
}

return(
<div>
<h2>AI Assistant</h2>
<textarea placeholder="Describe interaction..." onChange={e=>setText(e.target.value)}/><br/>
<button onClick={ask}>Ask AI</button>
<pre>{res}</pre>
</div>
)
}
